s($,"b2Z","aLz",()=>A.ar([B.eZ,"import 'package:flutter/material.dart';\nimport 'package:flutter_monaco/flutter_monaco.dart';\n\nvoid main() => runApp(const DemoApp());\n\nclass DemoApp extends StatelessWidget {\n  const DemoApp({super.key});\n\n  @override\n  Widget build(BuildContext context) {\n    return const MaterialApp(\n      home: Scaffold(\n        body: MonacoEditor(\n          options: EditorOptions(\n            language: MonacoLanguage.dart,\n            theme: MonacoTheme.vsDark,\n          ),\n        ),\n      ),\n    );\n  }\n}\n",B.vs,"interface User {\n  id: string;\n  name: string;\n  roles: ReadonlyArray<'admin' | 'editor' | 'viewer'>;\n}\n\nasync function fetchUser(id: string): Promise<User> {\n  const res = await fetch(`/api/users/${id}`);\n  if (!res.ok) throw new Error(`HTTP ${res.status}`);\n  return res.json() as Promise<User>;\n}\n\nconst isAdmin = (u: User): boolean => u.roles.includes('admin');\n\nfetchUser('42').then((user) => {\n  console.log(`${user.name} is admin: ${isAdmin(user)}`);\n});\n",B.hO,"const pipe = (...fns) => (x) => fns.reduce((acc, fn) => fn(acc), x);\n\nconst clean = pipe(\n  (s) => s.trim(),\n  (s) => s.toLowerCase(),\n  (s) => s.replace(/\\s+/g, '-'),\n);\n\nconst slugify = (title) => clean(title);\n\nconsole.log(slugify('  Hello   Monaco World ')); // \"hello-monaco-world\"\n",B.vz,'from dataclasses import dataclass\nfrom typing import Iterable\n\n\n@dataclass(frozen=True)\nclass Point:\n    x: float\n    y: float\n\n    def distance_to(self, other: "Point") -> float:\n        return ((self.x - other.x) ** 2 + (self.y - other.y) ** 2) ** 0.5\n\n\ndef total_path(points: Iterable[Point]) -> float:\n    pts = list(points)\n    return sum(a.distance_to(b) for a, b in zip(pts, pts[1:]))\n\n\nprint(total_path([Point(0, 0), Point(3, 4), Point(3, 0)]))\n',B.l1,'#[derive(Debug, Clone)]\nstruct Stack<T> {\n    items: Vec<T>,\n}\n\nimpl<T> Stack<T> {\n    fn new() -> Self {\n        Stack { items: Vec::new() }\n    }\n\n    fn push(&mut self, value: T) {\n        self.items.push(value);\n    }\n\n    fn pop(&mut self) -> Option<T> {\n        self.items.pop()\n    }\n}\n\nfn main() {\n    let mut stack = Stack::new();\n    stack.push(1);\n    stack.push(2);\n    println!("{:?}", stack.pop());\n}\n',B.vu,'package main\n\nimport (\n\t"fmt"\n\t"sync"\n)\n\nfunc main() {\n\tvar wg sync.WaitGroup\n\tresults := make(chan int, 5)\n\n\tfor i := 1; i <= 5; i++ {\n\t\twg.Add(1)\n\t\tgo func(n int) {\n\t\t\tdefer wg.Done()\n\t\t\tresults <- n * n\n\t\t}(i)\n\t}\n\n\twg.Wait()\n\tclose(results)\n\n\tfor r := range results {\n\t\tfmt.Println("square:", r)\n\t}\n}\n',B.vA,"SELECT\n  u.id,\n  u.name,\n  COUNT(o.id) AS order_count,\n  SUM(o.total) AS lifetime_value\nFROM users AS u\nLEFT JOIN orders AS o ON o.user_id = u.id\nWHERE u.created_at >= '2025-01-01'\nGROUP BY u.id, u.name\nHAVING COUNT(o.id) > 3\nORDER BY lifetime_value DESC\nLIMIT 20;\n",B.vC,"name: deploy-web\non:\n  push:\n    branches: [main]\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: subosito/flutter-action@v2\n        with:\n          channel: stable\n      - run: flutter build web --release --wasm\n",B.vv,'<!DOCTYPE html>\n<html lang="en">\n  <head>\n    <meta charset="utf-8" />\n    <title>flutter_monaco</title>\n  </head>\n  <body>\n    <main class="hero">\n      <h1>VS Code\'s editor, inside Flutter.</h1>\n      <a class="cta" href="https://pub.dev/packages/flutter_monaco">\n        Get started\n      </a>\n    </main>\n  </body>\n</html>\n',B.vt,":root {\n  --accent: #0098ff;\n  --accent-2: #6e5bff;\n}\n\n.button {\n  padding: 12px 20px;\n  border-radius: 12px;\n  color: #fff;\n  background: linear-gradient(135deg, var(--accent), var(--accent-2));\n  transition: transform 160ms ease;\n}\n\n.button:hover {\n  transform: translateY(-2px);\n}\n",B.vw,'import java.util.List;\nimport java.util.stream.Collectors;\n\npublic class Greeter {\n    public static void main(String[] args) {\n        List<String> names = List.of("Ada", "Linus", "Grace");\n\n        String greeting = names.stream()\n            .map(name -> "Hello, " + name + "!")\n            .collect(Collectors.joining("\\n"));\n\n        System.out.println(greeting);\n    }\n}\n',B.vx,'data class Task(val title: String, val done: Boolean = false)\n\nfun main() {\n    val tasks = listOf(\n        Task("Wire up the editor"),\n        Task("Ship the demo", done = true),\n        Task("Tweet about it"),\n    )\n\n    val (completed, pending) = tasks.partition { it.done }\n    println("Done: ${completed.size}, Pending: ${pending.size}")\n    pending.forEach { println(" - ${it.title}") }\n}\n',B.vB,'import Foundation\n\nstruct Temperature {\n    var celsius: Double\n    var fahrenheit: Double { celsius * 9 / 5 + 32 }\n}\n\nlet readings = [Temperature(celsius: 0),\n                Temperature(celsius: 37),\n                Temperature(celsius: 100)]\n\nfor reading in readings {\n    print("\\(reading.celsius)C = \\(reading.fahrenheit)F")\n}\n'],A.a3("dz"),t.N))
